     1→/**
     2→ * API Error Handler Middleware
     3→ * Provides consistent error handling for API routes
     4→ */
     5→
     6→import { NextResponse } from 'next/server';
     7→import { logger, generateRequestId, createRequestLogger } from '@/server/lib/logger';
     8→import { CircuitBreakerOpenError } from './rate-limiter';
     9→
    10→/**
    11→ * Standard API error response structure
    12→ */
    13→export interface ApiErrorResponse {
    14→  error: {
    15→    message: string;
    16→    code: string;
    17→    details?: unknown;
    18→  };
    19→}
    20→
    21→/**
    22→ * Custom API error class with status code and error code
    23→ */
    24→export class ApiError extends Error {
    25→  constructor(
    26→    public readonly statusCode: number,
    27→    public readonly code: string,
    28→    message: string,
    29→    public readonly details?: unknown
    30→  ) {
    31→    super(message);
    32→    this.name = 'ApiError';
    33→  }
    34→
    35→  /**
    36→   * Factory method for 400 Bad Request
    37→   */
    38→  static badRequest(message: string, details?: unknown): ApiError {
    39→    return new ApiError(400, 'BAD_REQUEST', message, details);
    40→  }
    41→
    42→  /**
    43→   * Factory method for 401 Unauthorized
    44→   */
    45→  static unauthorized(message = 'Unauthorized'): ApiError {
    46→    return new ApiError(401, 'UNAUTHORIZED', message);
    47→  }
    48→
    49→  /**
    50→   * Factory method for 403 Forbidden
    51→   */
    52→  static forbidden(message = 'Forbidden'): ApiError {
    53→    return new ApiError(403, 'FORBIDDEN', message);
    54→  }
    55→
    56→  /**
    57→   * Factory method for 404 Not Found
    58→   */
    59→  static notFound(message = 'Resource not found'): ApiError {
    60→    return new ApiError(404, 'NOT_FOUND', message);
    61→  }
    62→
    63→  /**
    64→   * Factory method for 429 Too Many Requests
    65→   */
    66→  static tooManyRequests(message = 'Too many requests'): ApiError {
    67→    return new ApiError(429, 'TOO_MANY_REQUESTS', message);
    68→  }
    69→
    70→  /**
    71→   * Factory method for 500 Internal Server Error
    72→   */
    73→  static internal(message = 'Internal server error', details?: unknown): ApiError {
    74→    return new ApiError(500, 'INTERNAL_ERROR', message, details);
    75→  }
    76→
    77→  /**
    78→   * Factory method for 503 Service Unavailable
    79→   */
    80→  static serviceUnavailable(message = 'Service temporarily unavailable'): ApiError {
    81→    return new ApiError(503, 'SERVICE_UNAVAILABLE', message);
    82→  }
    83→}
    84→
    85→/**
    86→ * Convert error to standardized API response
    87→ */
    88→export function toErrorResponse(error: unknown): {
    89→  response: ApiErrorResponse;
    90→  status: number;
    91→  headers?: Record<string, string>;
    92→} {
    93→  if (error instanceof ApiError) {
    94→    return {
    95→      response: {
    96→        error: {
    97→          message: error.message,
    98→          code: error.code,
    99→          details: error.details,
   100→        },
   101→      },
   102→      status: error.statusCode,
   103→    };
   104→  }
   105→
   106→  // Handle circuit breaker open errors
   107→  if (error instanceof CircuitBreakerOpenError) {
   108→    logger.warn({ retryAfter: error.retryAfter }, 'Circuit breaker is open');
   109→    return {
   110→      response: {
   111→        error: {
   112→          message: 'Service temporarily unavailable. Please try again later.',
   113→          code: 'SERVICE_UNAVAILABLE',
   114→          details: { retryAfter: error.retryAfter },
   115→        },
   116→      },
   117→      status: 503,
   118→      headers: {
   119→        'Retry-After': String(error.retryAfter),
   120→      },
   121→    };
   122→  }
   123→
   124→  // Handle standard Error objects
   125→  if (error instanceof Error) {
   126→    logger.error({ error: error.message, stack: error.stack }, 'Unhandled error');
   127→    return {
   128→      response: {
   129→        error: {
   130→          message: 'An unexpected error occurred',
   131→          code: 'INTERNAL_ERROR',
   132→        },
   133→      },
   134→      status: 500,
   135→    };
   136→  }
   137→
   138→  // Handle unknown error types
   139→  logger.error({ error }, 'Unknown error type');
   140→  return {
   141→    response: {
   142→      error: {
   143→        message: 'An unexpected error occurred',
   144→        code: 'INTERNAL_ERROR',
   145→      },
   146→    },
   147→    status: 500,
   148→  };
   149→}
   150→
   151→/**
   152→ * Wrap API route handler with error handling
   153→ * Usage:
   154→ * ```ts
   155→ * export const GET = withErrorHandler(async (request) => {
   156→ *   // Your logic here
   157→ *   return NextResponse.json({ data: 'success' });
   158→ * });
   159→ * ```
   160→ */
   161→export function withErrorHandler<T extends (...args: never[]) => Promise<Response>>(handler: T): T {
   162→  return (async (...args: Parameters<T>): Promise<Response> => {
   163→    const requestId = generateRequestId();
   164→    const log = createRequestLogger(requestId);
   165→
   166→    try {
   167→      return await handler(...args);
   168→    } catch (error) {
   169→      const { response, status, headers } = toErrorResponse(error);
   170→      log.error({ error, status }, 'Request failed');
   171→      return NextResponse.json(response, {
   172→        status,
   173→        headers: {
   174→          ...headers,
   175→          'X-Request-Id': requestId,
   176→        },
   177→      });
   178→    }
   179→  }) as T;
   180→}
   181→
   182→/**
   183→ * Helper function to create error response directly
   184→ */
   185→export function errorResponse(
   186→  statusCode: number,
   187→  code: string,
   188→  message: string,
   189→  details?: unknown
   190→): NextResponse<ApiErrorResponse> {
   191→  return NextResponse.json(
   192→    {
   193→      error: {
   194→        message,
   195→        code,
   196→        details,
   197→      },
   198→    },
   199→    { status: statusCode }
   200→  );
   201→}
